bool ProjectInfo::validateJsonForCreation(const Json::Value &pJson, std::string &err)
{
    if(pJson.isMember("id"))
    {
        if(!validJsonOfField(0, "id", pJson["id"], err, true))
            return false;
    }
    if(pJson.isMember("name"))
    {
        if(!validJsonOfField(1, "name", pJson["name"], err, true))
            return false;
    }
    else
    {
        err="The name column cannot be null";
        return false;
    }
    if(pJson.isMember("developer"))
    {
        if(!validJsonOfField(2, "developer", pJson["developer"], err, true))
            return false;
    }
    if(pJson.isMember("scale"))
    {
        if(!validJsonOfField(3, "scale", pJson["scale"], err, true))
            return false;
    }
    if(pJson.isMember("description"))
    {
        if(!validJsonOfField(4, "description", pJson["description"], err, true))
            return false;
    }
    if(pJson.isMember("map_lat"))
    {
        if(!validJsonOfField(5, "map_lat", pJson["map_lat"], err, true))
            return false;
    }
    if(pJson.isMember("map_lng"))
    {
        if(!validJsonOfField(6, "map_lng", pJson["map_lng"], err, true))
            return false;
    }
    if(pJson.isMember("map_zoom"))
    {
        if(!validJsonOfField(7, "map_zoom", pJson["map_zoom"], err, true))
            return false;
    }
    if(pJson.isMember("updated_by"))
    {
        if(!validJsonOfField(8, "updated_by", pJson["updated_by"], err, true))
            return false;
    }
    if(pJson.isMember("updated_at"))
    {
        if(!validJsonOfField(9, "updated_at", pJson["updated_at"], err, true))
            return false;
    }
    return true;
}
